#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long a,b;
    bool operator<(const node&b1)const
    {
        return b<b1.b;
    }
}a[1000010],b[1000010];
int main()
{
    long long n,m=0;
    long long max1=0;
    scanf("%lld",&n);
    long long k=0;
    for(long long i=1;i<=n;i++)
    {
        long long a,b;
        scanf("%lld%lld",&a,&b);
        max1=max({max1,a,b});
        if(a>b)
        {
            ::a[++k].a=a;
            ::a[k].b=b;
        }
    }
    sort(a+1,a+1+k);
    long long l=-1,r=-1;
    for(long long i=1;i<=k;i++)
    {
        b[++m]=(node){a[i].a,a[i].b};
    }
    long long ans=LLONG_MAX,sum=0;
    sort(b+1,b+1+m);
    long long maxa=0;
    for(long long i=1;i<=m;i++)
    {
        ans=min(ans,sum+max1-b[i].b);
        sum+=2*max(0ll,(b[i].a-max(maxa,b[i].b)));
        maxa=max(maxa,b[i].a);
    }
    printf("%lld",min(sum,ans)+max1);
    return 0;
}
